16	package io.github.glaforge.agybrainviz;
17	
18	import io.micronaut.core.annotation.Nullable;
19	import io.micronaut.http.HttpHeaders;
20	import io.micronaut.http.HttpRequest;
21	import io.micronaut.http.HttpResponse;
22	import io.micronaut.http.HttpStatus;
23	import io.micronaut.http.annotation.RequestFilter;
24	import io.micronaut.http.annotation.ServerFilter;
25	import jakarta.inject.Inject;
26	import jakarta.inject.Singleton;
27	import java.nio.charset.StandardCharsets;
28	import java.security.MessageDigest;
29	import java.util.Map;
30	import java.util.Optional;
31	
32	/**
33	 * Guards the ingest endpoints with a shared bearer token when {@code INGEST_TOKEN} is set.
34	 *
35	 * <p>These are the only endpoints that write, and the only ones a remote machine calls, so they are
36	 * the only ones worth guarding. With no token configured the filter waves everything through — the
37	 * server is then presumed to be listening on localhost only.
38	 */
39	@Singleton
40	@ServerFilter("/api/ingest/**")
41	public class IngestAuthFilter {
42	
43	    private static final String BEARER = "Bearer ";
44	
45	    private final IngestConfig config;
46	
47	    @Inject
48	    public IngestAuthFilter(IngestConfig config) {
49	        this.config = config;
50	    }
51	
52	    /** @return a 401/503 to short-circuit the request, or {@code null} to let it proceed. */
53	    @RequestFilter
54	    @Nullable
55	    public HttpResponse<?> guard(HttpRequest<?> request) {
56	        Optional<String> expected = config.token();
57	        if (expected.isEmpty()) {
58	            // No token configured. Normally that's the localhost-only default, so wave through — but
59	            // if the operator opted into INGEST_REQUIRE_AUTH they want auth enforced, and there is no
60	            // token any request could present. Fail closed: reject with a 503 (a server-side
61	            // misconfiguration the client can't fix by authenticating), never fall back to open. The
62	            // body stays generic — the specific cause (missing INGEST_TOKEN) is for the operator's
63	            // startup log, not an unauthenticated caller.
64	            if (config.requireAuth()) {
65	                return HttpResponse
66	                    .status(HttpStatus.SERVICE_UNAVAILABLE)
67	                    .body(Map.of("error", "Ingest is unavailable."));
68	            }
69	            return null; // unguarded by configuration
70	        }
71	
72	        String header = request.getHeaders().get(HttpHeaders.AUTHORIZATION);
73	        if (header == null || !header.startsWith(BEARER) || !matches(expected.get(), header)) {
74	            return HttpResponse
75	                .unauthorized()
76	                .body(
77	                    Map.of("error", "Ingest requires a valid Authorization: Bearer <INGEST_TOKEN>.")
78	                );
79	        }
80	        return null;
81	    }
82	
83	    // Compare without leaking the token's length or contents through timing.
84	    private static boolean matches(String expected, String header) {
85	        byte[] presented = header
86	            .substring(BEARER.length())
87	            .trim()
88	            .getBytes(StandardCharsets.UTF_8);
89	        return MessageDigest.isEqual(expected.getBytes(StandardCharsets.UTF_8), presented);
90	    }
91	}
