16	package io.github.glaforge.agybrainviz;
17	
18	import jakarta.inject.Inject;
19	import jakarta.inject.Singleton;
20	import java.util.Locale;
21	import java.util.Optional;
22	
23	/**
24	 * Whether the ingest endpoints require a shared secret.
25	 *
26	 * <p>{@code INGEST_TOKEN} is read from a real environment variable, else a {@code .env} file. Unset
27	 * leaves {@code /api/ingest} open, which is the right default while the server only listens on
28	 * localhost. Set it as soon as the server is reachable from another machine — those endpoints are the
29	 * only ones that write.
30	 *
31	 * <p>{@code INGEST_REQUIRE_AUTH} is an opt-in fail-closed switch for operators who never want the
32	 * open default: when it is truthy, {@link IngestAuthFilter} rejects all ingest until a token is
33	 * configured, so a missing {@code INGEST_TOKEN} can't silently leave the writes exposed.
34	 *
35	 * <p>Reading through this bean (rather than {@code System.getenv} inline) gives {@link
36	 * IngestAuthFilter} a test seam, matching {@link AiConfig}.
37	 */
38	@Singleton
39	public class IngestConfig {
40	
41	    private final String ingestToken;
42	    private final boolean requireAuth;
43	
44	    @Inject
45	    public IngestConfig() {
46	        this(env("INGEST_TOKEN"), parseFlag(env("INGEST_REQUIRE_AUTH")));
47	    }
48	
49	    // Test seam: an explicit token with the open default (auth not required).
50	    IngestConfig(String ingestToken) {
51	        this(ingestToken, false);
52	    }
53	
54	    // Test seam: construct with explicit values, bypassing the environment.
55	    IngestConfig(String ingestToken, boolean requireAuth) {
56	        this.ingestToken = ingestToken;
57	        this.requireAuth = requireAuth;
58	    }
59	
60	    /** @return the shared token, or empty when the ingest endpoints are unguarded. */
61	    public Optional<String> token() {
62	        return (ingestToken == null || ingestToken.isBlank())
63	            ? Optional.empty()
64	            : Optional.of(ingestToken.trim());
65	    }
66	
67	    /** @return whether ingest must be authenticated, even at the cost of rejecting it when no token is set. */
68	    public boolean requireAuth() {
69	        return requireAuth;
70	    }
71	
72	    /** Reads a boolean-ish env flag: {@code true}/{@code 1}/{@code yes}/{@code on} (any case) is true. */
73	    static boolean parseFlag(String value) {
74	        if (value == null) return false;
75	        return switch (value.trim().toLowerCase(Locale.ROOT)) {
76	            case "true", "1", "yes", "on" -> true;
77	            default -> false;
78	        };
79	    }
80	
81	    private static String env(String key) {
82	        String value = System.getenv(key);
83	        if (value == null) value = DotEnv.get(key);
84	        return value == null ? "" : value;
85	    }
86	}
