27	export function escapeHtml(unsafe) {
28	  if (!unsafe) return "";
29	  return String(unsafe)
30	    .replace(/&/g, "&amp;")
31	    .replace(/</g, "&lt;")
32	    .replace(/>/g, "&gt;")
33	    .replace(/"/g, "&quot;")
34	    .replace(/'/g, "&#039;");
35	}
36	
37	export function syntaxHighlight(json) {
38	  if (typeof json != "string") {
39	    json = JSON.stringify(json, undefined, 2);
40	  }
41	  json = json
42	    .replace(/&/g, "&amp;")
43	    .replace(/</g, "&lt;")
44	    .replace(/>/g, "&gt;");
45	  return json.replace(
46	    /("(\\u[a-zA-Z0-9]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+\-]?\d+)?)/g,
47	    function (match) {
48	      var cls = "json-number";
49	      if (/^"/.test(match)) {
50	        if (/:$/.test(match)) {
51	          cls = "json-key";
52	        } else {
53	          cls = "json-string";
54	        }
55	      } else if (/true|false/.test(match)) {
56	        cls = "json-boolean";
57	      } else if (/null/.test(match)) {
58	        cls = "json-null";
59	      }
60	      return '<span class="' + cls + '">' + match + "</span>";
61	    }
62	  );
63	}
