65	export function formatTime(dateStr, withSeconds = false) {
66	  if (!dateStr) return "";
67	  const d = new Date(dateStr);
68	  if (state.spansMultipleDays) {
69	    if (withSeconds) {
70	      return (
71	        d.toLocaleDateString([], { month: "short", day: "numeric" }) +
72	        ", " +
73	        d.toLocaleTimeString([], { hour12: false })
74	      );
75	    } else {
76	      return (
77	        d.toLocaleDateString([], { month: "short", day: "numeric" }) +
78	        ", " +
79	        d.toLocaleTimeString([], {
80	          hour: "2-digit",
81	          minute: "2-digit",
82	          hour12: false,
83	        })
84	      );
85	    }
86	  } else {
87	    if (withSeconds) {
88	      return d.toLocaleTimeString([], { hour12: false });
89	    } else {
90	      return d.toLocaleTimeString([], {
91	        hour: "2-digit",
92	        minute: "2-digit",
93	        hour12: false,
94	      });
95	    }
96	  }
97	}
