99	export function updateTranscriptFilter() {
100	  const cards = document.querySelectorAll(".step-card");
101	  const { userQueries, toolsCalled, outcomeErrors, modelResponses } =
102	    state.activeFilters;
103	
104	  if (!userQueries && !toolsCalled && !outcomeErrors && !modelResponses) {
105	    cards.forEach((c) => (c.style.display = "block"));
106	    return;
107	  }
108	
109	  cards.forEach((c) => {
110	    const isUser = c.dataset.isUser === "true";
111	    const isTool = c.dataset.isTool === "true";
112	    const isError = c.dataset.isError === "true";
113	    const isModel = c.dataset.isModel === "true";
114	
115	    let show = false;
116	    if (userQueries && isUser) show = true;
117	    if (toolsCalled && isTool) show = true;
118	    if (outcomeErrors && isError) show = true;
119	    if (modelResponses && isModel) show = true;
120	
121	    c.style.display = show ? "block" : "none";
122	  });
123	
124	  const wrappers = document.querySelectorAll(".sequence-wrapper");
125	  wrappers.forEach((wrapper) => {
126	    const hasVisibleCard = Array.from(
127	      wrapper.querySelectorAll(".step-card")
128	    ).some((c) => c.style.display === "block");
129	    wrapper.style.display = hasVisibleCard ? "block" : "none";
130	  });
131	}
