34	/** Serves the session list and transcripts from the shared store, keyed by {@code flavor}/source. */
35	@Controller("/api/brain")
36	public class BrainController {
37	
38	    private final SessionRepository sessions;
39	
40	    @Inject
41	    public BrainController(SessionRepository sessions) {
42	        this.sessions = sessions;
43	    }
44	
45	    /** Default page size when the client asks for none — enough to fill the sidebar in one load. */
46	    static final int DEFAULT_LIMIT = 200;
47	    /** Hard cap so a client can never make the store return an unbounded list in one response. */
48	    static final int MAX_LIMIT = 1000;
49	
50	    /**
51	     * One page of a source's sessions, newest first. The list is paged so a large store never has to
52	     * be returned (or rendered) all at once; the client loads more on demand and uses {@code total} to
53	     * know when it has them all.
54	     */
55	    @ExecuteOn(TaskExecutors.IO)
56	    @Get("/conversations")
57	    public ConversationPage listConversations(
58	        @QueryValue Optional<String> flavor,
59	        @QueryValue Optional<Integer> limit,
60	        @QueryValue Optional<Integer> offset
61	    ) {
62	        String source = flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR);
63	        int pageLimit = clamp(limit.orElse(DEFAULT_LIMIT), 1, MAX_LIMIT);
64	        int pageOffset = Math.max(0, offset.orElse(0));
65	        List<Map<String, String>> items = sessions.listConversations(source, pageLimit, pageOffset);
66	        return new ConversationPage(items, sessions.countBySource(source), pageLimit, pageOffset);
67	    }
68	
69	    private static int clamp(int value, int min, int max) {
70	        return Math.max(min, Math.min(max, value));
71	    }
72	
73	    @ExecuteOn(TaskExecutors.IO)
74	    @Get(value = "/conversations/{id}/transcript", produces = "application/json")
75	    public String getTranscript(@PathVariable String id, @QueryValue Optional<String> flavor) {
76	        String steps = sessions.steps(flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR), id);
77	        return steps != null ? steps : "[]";
78	    }
79	
80	    /**
81	     * Serves a referenced file's contents for the inline preview.
82	     *
83	     * <p>This one endpoint is inherently machine-local: Antigravity transcripts link to files under
84	     * the user's {@code ~/.gemini}, which live on the machine that ran the agent, not in the store. On
85	     * a different machine the file simply isn't there, and the preview returns not-found — the one
86	     * honest exception to reads coming from the store.
87	     */
88	    @ExecuteOn(TaskExecutors.IO)
89	    @Get(value = "/file", produces = "text/plain")
90	    public HttpResponse<String> getFileContent(@QueryValue String path) {
91	        try {
92	            Path filePath = Paths.get(path).normalize();
93	            Path geminiDir = AntigravityPaths.geminiRoot().normalize();
94	            if (!filePath.startsWith(geminiDir)) {
95	                return HttpResponse.unauthorized();
96	            }
97	            if (Files.exists(filePath) && !Files.isDirectory(filePath)) {
98	                return HttpResponse.ok(Files.readString(filePath));
99	            } else {
100	                return HttpResponse.notFound("File not available on this machine.");
101	            }
102	        } catch (IOException e) {
103	            return HttpResponse.serverError("Error reading file: " + e.getMessage());
104	        }
105	    }
106	}
