222	export function filterAndSortConversations(
223	  conversations,
224	  searchTerm,
225	  descending
226	) {
227	  let filtered = [...conversations];
228	  const term = (searchTerm || "").toLowerCase();
229	  if (term) {
230	    filtered = filtered.filter(
231	      (c) =>
232	        c.summary.toLowerCase().includes(term) ||
233	        c.id.toLowerCase().includes(term)
234	    );
235	  }
236	  if (!descending) {
237	    filtered.reverse();
238	  }
239	  return filtered;
240	}
