242	export async function loadConversations() {
243	  const list = document.getElementById("conversations-list");
244	  const flavor = encodeURIComponent(
245	    document.getElementById("flavor-select").value
246	  );
247	  try {
248	    const res = await fetch(
249	      `/api/brain/conversations?flavor=${flavor}&limit=${CONV_PAGE_SIZE}&offset=0`
250	    );
251	    if (!res.ok) throw new Error(`HTTP ${res.status}`);
252	    const page = await res.json();
253	    allConversations = page.items || [];
254	    convTotal = page.total ?? allConversations.length;
255	    announceConversations();
256	    // Only the first load auto-selects (deep-link or newest session); re-renders must not.
257	    renderConversationsList(true);
258	    // A reachable-but-empty store is the first-run case: guide the user to import instead of
259	    // leaving the main pane on the "select a session" prompt when there are none to select.
260	    if (convTotal === 0) showEmptyStoreOnboarding();
261	  } catch (e) {
262	    list.innerHTML =
263	      '<div class="loading-state" style="padding:16px;">Error loading sessions. Is the backend running?</div>';
264	  }
265	}
