44	    private static final int MAX_TOKENS_PER_CHUNK = 100_000;
45	    private static final Map<String, ProgressState> progressMap = new ConcurrentHashMap<>();
46	
47	    @Serdeable
48	    public record ProgressState(int progress, String phase) {}
