50	    @Get(value = "/conversations/{id}/progress", produces = "application/json")
51	    public ProgressResponse getProgress(@PathVariable String id) {
52	        ProgressState state = progressMap.get(id);
53	        if (state == null) {
54	            return new ProgressResponse("", -1);
55	        }
56	        return new ProgressResponse(state.phase(), state.progress());
57	    }
