59	    @Serdeable
60	    public record ProgressResponse(String phase, int progress) {}
61	
62	    private final AnalyzerService analyzerService;
63	    private final ExecutorService executor;
64	    private final AiConfig aiConfig;
65	    private final TokenCounter tokenCounter;
66	    private final SessionRepository sessions;
