69	    @Inject
70	    public AnalysisController(
71	        AnalyzerService analyzerService,
72	        @Named(TaskExecutors.IO) ExecutorService executor,
73	        AiConfig aiConfig,
74	        TokenCounter tokenCounter,
75	        SessionRepository sessions,
76	        SummaryRepository summaries
77	    ) {
78	        this.analyzerService = analyzerService;
79	        this.executor = executor;
80	        this.aiConfig = aiConfig;
81	        this.tokenCounter = tokenCounter;
82	        this.sessions = sessions;
83	        this.summaries = summaries;
84	    }
85	
86	    private static final Map<String, Object> runningTasks = new ConcurrentHashMap<>();
87	
88	    @ExecuteOn(TaskExecutors.IO)
89	    @Get(value = "/conversations/{id}/summarize", produces = "application/json")
90	    public String summarizeConversation(
91	        @PathVariable String id,
92	        @QueryValue Optional<Boolean> force,
93	        @QueryValue Optional<String> flavor
94	    ) throws IOException {
95	        if (!aiConfig.isConfigured()) {
96	            // Serialize via Jackson so the message is always valid JSON, regardless of its content.
97	            return new ObjectMapper()
98	                .writeValueAsString(Map.of("summary", aiConfig.notConfiguredMessage()));
99	        }
100	
101	        if (runningTasks.putIfAbsent(id, new Object()) != null) {
102	            return "{\"summary\": \"Analysis is already running in the background for this conversation. Please wait a moment and refresh.\"}";
103	        }
104	
105	        try {
106	            String flavorName = flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR);
107	            boolean forceRecompute = force.orElse(false);
108	
109	            if (!sessions.exists(flavorName, id)) {
110	                return "{\"summary\": \"No transcript found.\"}";
111	            }
112	
113	            if (!forceRecompute) {
114	                Optional<String> cached = summaries.find(flavorName, id);
115	                if (cached.isPresent()) {
116	                    return cached.get();
117	                }
118	            } else {
119	                summaries.delete(flavorName, id);
120	            }
121	
122	            ObjectMapper mapper = new ObjectMapper();
123	            AnalysisResponse responseObj = null;
124	            boolean consolidationFellBack = false;
125	
126	            try {
127	                List<List<String>> sequences = AnalysisSequences.fromStepsJson(
128	                    flavorName,
129	                    sessions.steps(flavorName, id)
130	                );
131	
132	                ToIntFunction<String> tokenFn = tokenCounter::estimate;
133	
134	                progressMap.put(id, new ProgressState(5, "Estimating Tokens & Chunking...")); // Phase 1: Estimating
135	
136	                List<String> combinedLines = new ArrayList<>();
137	                for (List<String> seq : sequences) {
138	                    combinedLines.addAll(seq);
139	                }
140	                List<List<String>> optimalChunks = new ArrayList<>();
141	                TranscriptParser.splitIntoSafeChunks(
142	                    combinedLines,
143	                    tokenFn,
144	                    MAX_TOKENS_PER_CHUNK,
145	                    optimalChunks
146	                );
147	
148	                System.out.println(
149	                    "Total optimal chunks to process in parallel: " + optimalChunks.size()
150	                );

150	                );
151	
152	                progressMap.put(id, new ProgressState(0, "Starting chunk processing...")); // start at 0%
153	
154	                List<Future<AnalysisResponse>> futures = new ArrayList<>();
155	                AtomicInteger completed = new AtomicInteger(0);
156	
157	                // Limit to 20 concurrent LLM requests, as we have drastically reduced chunk count
158	                Semaphore rateLimitSemaphore = new Semaphore(20);
159	
160	                for (List<String> chunkLines : optimalChunks) {
161	                    futures.add(
162	                        executor.submit(() -> {
163	                            try {
164	                                rateLimitSemaphore.acquire();
165	                            } catch (InterruptedException e) {
166	                                Thread.currentThread().interrupt();
167	                                return null;
168	                            }
169	
170	                            try {
171	                                String chunk = String.join("\n", chunkLines);
172	                                AnalysisResponse seqResponse = null;
173	                                try {
174	                                    seqResponse = analyzerService.analyze(chunk);
175	                                } catch (Exception e) {
176	                                    System.err.println(
177	                                        "Failed to parse chunk from LLM: " + e.getMessage()
178	                                    );
179	                                    e.printStackTrace();
180	                                    // Ignore unparseable chunk
181	                                }
182	
183	                                int comp = completed.incrementAndGet();
184	                                // Scale parallel processing to 90% of the total progress
185	                                int pct = (int) Math.round((comp * 90.0) / optimalChunks.size());
186	                                String phaseMsg =
187	                                    "Processing chunk " +
188	                                    comp +
189	                                    " of " +
190	                                    optimalChunks.size() +
191	                                    "...";
192	
193	                                // Prevent progress moving backwards if futures finish out of order
194	                                progressMap.compute(
195	                                    id,
196	                                    (k, v) -> {
197	                                        if (v == null || pct > v.progress()) {
198	                                            return new ProgressState(pct, phaseMsg);
199	                                        }
200	                                        return v;
201	                                    }
202	                                );
203	
204	                                return seqResponse;
205	                            } finally {
206	                                rateLimitSemaphore.release();
207	                            }
208	                        })
209	                    );
210	                }
211	
212	                List<AnalysisResponse> seqResponses = new ArrayList<>();
213	                for (Future<AnalysisResponse> f : futures) {
214	                    AnalysisResponse r = f.get();
215	                    if (r != null) seqResponses.add(r);
216	                }
217	
218	                if (seqResponses.isEmpty()) {
219	                    // Distinguish "nothing to analyze" from "the model failed for every chunk".
220	                    String msg = optimalChunks.isEmpty()
221	                        ? "No transcript lines found."
222	                        : "Analysis could not be generated: the model did not return a result for any part of this conversation. Please try again.";
223	                    return mapper.writeValueAsString(Map.of("summary", msg));
224	                } else if (seqResponses.size() == 1) {
225	                    responseObj = seqResponses.get(0);
226	                } else {
227	                    progressMap.put(id, new ProgressState(90, "Consolidating final analysis..."));
228	
229	                    // Keep the progress bar moving smoothly during the long final LLM consolidation
230	                    AtomicBoolean consolidationDone = new AtomicBoolean(false);
231	                    Future<?> fakeProgress = executor.submit(() -> {
232	                        int p = 90;
233	                        while (!consolidationDone.get() && p < 99) {
234	                            try {
235	                                Thread.sleep(2000);
236	                            } catch (InterruptedException e) {
237	                                break;
238	                            }
239	                            if (!consolidationDone.get()) {
240	                                int nextP = p + 1;
241	                                progressMap.put(
242	                                    id,
243	                                    new ProgressState(nextP, "Consolidating final analysis...")
244	                                );
245	                                p = nextP;
246	                            }
247	                        }
248	                    });
249	
250	                    try {
251	                        responseObj =
252	                            recursivelyConsolidate(seqResponses, tokenFn, mapper, 500_000);
253	                    } catch (Exception e) {
254	                        // LLM consolidation failed (e.g. API timeout). Rather than discard all the
255	                        // per-chunk work, merge the partial analyses locally so the user still gets
256	                        // a usable summary.
257	                        System.err.println(
258	                            "Consolidation failed; using local merge fallback: " + e.getMessage()
259	                        );
260	                        responseObj = localMerge(seqResponses);
261	                        consolidationFellBack = true;
262	                    } finally {
263	                        consolidationDone.set(true);
264	                        fakeProgress.cancel(true);
265	                    }
266	                }
267	
268	                progressMap.put(id, new ProgressState(100, "Done"));
269	
270	                String jsonResponse = mapper.writeValueAsString(responseObj);
271	
272	                // Don't persist a degraded local-merge fallback: the consolidation failure was
273	                // likely transient, so a later (non-forced) load should retry the LLM rather than
274	                // serve the cruder summary.
275	                if (consolidationFellBack) {
276	                    return jsonResponse;
277	                }
278	
279	                String title = responseObj.shortTitle();
280	                // Caching is best-effort: a store hiccup must not discard a summary we just computed.
281	                // Log it, though — a persistently failing cache silently re-spends tokens every load.
282	                try {
283	                    summaries.upsert(flavorName, id, jsonResponse, title);
284	                } catch (Exception e) {
285	                    System.err.println(
286	                        "Could not cache the summary for " + id + ": " + e.getMessage()
287	                    );
288	                }
289	                return jsonResponse;
290	            } catch (Exception e) {
291	                System.err.println("Exception caught during analysis:");
292	                e.printStackTrace();
293	                try {
294	                    return mapper.writeValueAsString(
295	                        Map.of("summary", "Error generating summary: " + e.getMessage())
296	                    );
297	                } catch (Exception ex) {
298	                    return "{\"summary\": \"Error generating summary: Unknown error\"}";
299	                }
300	            } finally {
301	                progressMap.remove(id);
302	            }
303	        } finally {
304	            runningTasks.remove(id);
305	        }
306	    }
307	
308	    private AnalysisResponse recursivelyConsolidate(
309	        List<AnalysisResponse> responses,
310	        ToIntFunction<String> tokenFn,
311	        ObjectMapper mapper,
312	        int maxTokens
313	    ) throws Exception {
314	        String json = mapper.writeValueAsString(responses);
315	        boolean withinBudget;
316	        try {
317	            withinBudget = tokenFn.applyAsInt(json) <= maxTokens;
318	        } catch (Exception e) {
319	            // Only token estimation is best-effort here; fall back to a char-length heuristic so a
320	            // failed estimate doesn't get mistaken for a failed consolidation.
321	            withinBudget = (json.length() / 4) <= maxTokens;
322	        }
323	        // A consolidation failure below propagates to the caller (which falls back to a local merge).
324	        if (withinBudget || responses.size() <= 1) {
325	            return analyzerService.consolidateAnalysis(json);
326	        }
327	
328	        int mid = responses.size() / 2;
329	        AnalysisResponse r1 = recursivelyConsolidate(
330	            responses.subList(0, mid),
331	            tokenFn,
332	            mapper,
333	            maxTokens
334	        );
335	        AnalysisResponse r2 = recursivelyConsolidate(
336	            responses.subList(mid, responses.size()),
337	            tokenFn,
338	            mapper,
339	            maxTokens
340	        );
341	        return analyzerService.consolidateAnalysis(mapper.writeValueAsString(List.of(r1, r2)));
342	    }
343	
344	    /**
345	     * Deterministically merges per-chunk analyses without calling the LLM. Used as a fallback when
346	     * LLM consolidation fails, so the user still gets a usable (if less polished) summary instead of
347	     * an error.
348	     */
349	    private AnalysisResponse localMerge(List<AnalysisResponse> responses) {
350	        String shortTitle = "Session analysis";
351	        StringBuilder summary = new StringBuilder();
352	        List<String> flow = new ArrayList<>();
353	        List<AgentAction> actions = new ArrayList<>();
354	        List<Issue> issues = new ArrayList<>();
355	        List<String> recommendations = new ArrayList<>();
356	
357	        for (AnalysisResponse r : responses) {
358	            if (r == null) continue;
359	            if (
360	                "Session analysis".equals(shortTitle) &&
361	                r.shortTitle() != null &&
362	                !r.shortTitle().isBlank()
363	            ) {
364	                shortTitle = r.shortTitle();
365	            }
366	            if (r.summary() != null && !r.summary().isBlank()) {
367	                if (summary.length() > 0) summary.append(" ");
368	                summary.append(r.summary().trim());
369	            }
370	            if (r.flow() != null) {
371	                for (String f : r.flow()) if (f != null && !flow.contains(f)) flow.add(f);
372	            }
373	            if (r.agentActions() != null) actions.addAll(r.agentActions());
374	            if (r.issues() != null) issues.addAll(r.issues());
375	            if (r.recommendations() != null) {
376	                for (String rec : r.recommendations()) {
377	                    if (rec != null && !recommendations.contains(rec)) recommendations.add(rec);
378	                }
379	            }
380	        }
381	
382	        String summaryText = summary.length() > 4000
383	            ? summary.substring(0, 4000) + "..."
384	            : summary.toString();
385	        summaryText =
386	            "(Combined from " +
387	            responses.size() +
388	            " partial analyses; full consolidation was unavailable.) " +
389	            summaryText;
390	
391	        return new AnalysisResponse(
392	            shortTitle,
393	            cap(flow, 40),
394	            cap(actions, 40),
395	            cap(issues, 40),
396	            cap(recommendations, 30),
397	            summaryText
398	        );
399	    }
400	
401	    private static <T> List<T> cap(List<T> list, int max) {
402	        return list.size() > max ? new ArrayList<>(list.subList(0, max)) : list;
403	    }
404	}
