export async function apiFetch(url, options = {}) {
  const doFetch = (token) => {
    const headers = { ...(options.headers || {}) };
    if (token) headers["Authorization"] = `Bearer ${token}`;
    return fetch(url, { ...options, headers });
  };
  let response = await doFetch(localStorage.getItem("agy-api-token") || "");
  if (response.status === 401) {
    const entered = window.prompt(
      "This server requires an API token (API_TOKEN). Enter it to continue:"
    );
    if (entered && entered.trim()) {
      localStorage.setItem("agy-api-token", entered.trim());
      response = await doFetch(entered.trim());
    }
  }
  return response;
}

